	ExecuteCommand(context.Context, *connect.Request[v1.ExecuteCommandRequest]) (*connect.Response[v1.ExecuteCommandResponse], error)
	// ── Plugins ────────────────────────────────────────────────────────
	ReloadPlugins(context.Context, *connect.Request[v1.ReloadPluginsRequest]) (*connect.Response[v1.ReloadPluginsResponse], error)
